var maxIncreaseKeepingSkyline = function(grid) {
    const n = grid.length;
    const rowMax = grid.map(row => Math.max(...row));
    const colMax = Array.from({length: n}, (_, c) => Math.max(...grid.map(r => grid[r][c])));
    let total = 0;
    for (let r = 0; r < n; r++)
        for (let c = 0; c < n; c++)
            total += Math.min(rowMax[r], colMax[c]) - grid[r][c];
    return total;
};

