var sortTransformedArray = function(nums, a, b, c) {
    const f = x => a*x*x + b*x + c;
    const n = nums.length;
    const result = new Array(n);
    let lo = 0, hi = n - 1;
    let idx = a >= 0 ? n - 1 : 0;
    while (lo <= hi) {
        const lv = f(nums[lo]), hv = f(nums[hi]);
        if (a >= 0) {
            if (lv >= hv) { result[idx--] = lv; lo++; }
            else { result[idx--] = hv; hi--; }
        } else {
            if (lv <= hv) { result[idx++] = lv; lo++; }
            else { result[idx++] = hv; hi--; }
        }
    }
    return result;
};

