        let nd1 = dp0 + 1;
        if (nums[i] >= nums[i-1]) nd1 = Math.max(nd1, dp1 + 1);
        dp0 = nd0; dp1 = nd1;
        ans = Math.max(ans, dp0, dp1);
    }
    return ans;
};

