class Solution:
    def uniquePathsIII(self, grid: List[List[int]]) -> int:
        rows, cols = len(grid), len(grid[0])
        start = end = None
        empty = 0
        for r in range(rows):
            for c in range(cols):
                if grid[r][c] != -1: empty += 1
                if grid[r][c] == 1: start = (r, c)
                if grid[r][c] == 2: end = (r, c)
        self.ans = 0
        def dfs(r, c, remaining):
            if (r, c) == end:
                if remaining == 1: self.ans += 1
                return
            tmp = grid[r][c]
            grid[r][c] = -1
            for dr, dc in [(1,0),(-1,0),(0,1),(0,-1)]:
                nr, nc = r+dr, c+dc
                if 0 <= nr < rows and 0 <= nc < cols and grid[nr][nc] != -1:
                    dfs(nr, nc, remaining - 1)
            grid[r][c] = tmp
        dfs(*start, empty)
        return self.ans

solution_js:
var uniquePathsIII = function(grid) {
    const rows = grid.length, cols = grid[0].length;
    let sr, sc, er, ec, empty = 0;
    for (let r = 0; r < rows; r++)
        for (let c = 0; c < cols; c++) {
            if (grid[r][c] !== -1) empty++;
            if (grid[r][c] === 1) { sr = r; sc = c; }
            if (grid[r][c] === 2) { er = r; ec = c; }
        }
    let ans = 0;
    function dfs(r, c, rem) {
        if (r === er && c === ec) { if (rem === 1) ans++; return; }
        const tmp = grid[r][c]; grid[r][c] = -1;
        for (const [dr, dc] of [[1,0],[-1,0],[0,1],[0,-1]]) {
            const nr = r+dr, nc = c+dc;
            if (nr >= 0 && nr < rows && nc >= 0 && nc < cols && grid[nr][nc] !== -1)
                dfs(nr, nc, rem - 1);
        }
        grid[r][c] = tmp;
    }
    dfs(sr, sc, empty);
    return ans;
};

