class Solution:
    def longestDupSubstring(self, s: str) -> str:
        n = len(s)
        nums = [ord(c) - ord('a') for c in s]
        MOD = (1 << 61) - 1
        BASE = 31

        def check(length):
            h = 0
            power = pow(BASE, length, MOD)
            for i in range(length):
                h = (h * BASE + nums[i]) % MOD
            seen = {h: [0]}
            for i in range(1, n - length + 1):
                h = (h * BASE - nums[i - 1] * power + nums[i + length - 1]) % MOD
                if h in seen:
                    for start in seen[h]:
                        if s[start:start + length] == s[i:i + length]:
                            return i
                    seen[h].append(i)
                else:
                    seen[h] = [i]
            return -1

        lo, hi = 0, n - 1
        start = 0
        best_len = 0
        while lo <= hi:
            mid = (lo + hi) // 2
            idx = check(mid)
            if idx != -1:
                best_len = mid
                start = idx
                lo = mid + 1
            else:
                hi = mid - 1
        return s[start:start + best_len]

solution_js:
var longestDupSubstring = function(s) {
    const n = s.length;
    const BASE = 31n, MOD = (1n << 61n) - 1n;
    const nums = Array.from(s, c => BigInt(c.charCodeAt(0) - 97));

    function check(length) {
        const power = modpow(BASE, BigInt(length), MOD);
        let h = 0n;
        for (let i = 0; i < length; i++) h = (h * BASE + nums[i]) % MOD;
        const seen = new Map([[h, [0]]]);
        for (let i = 1; i <= n - length; i++) {
            h = (h * BASE - nums[i - 1] * power % MOD + MOD + nums[i + length - 1]) % MOD;
            if (seen.has(h)) {
                for (const start of seen.get(h)) {
                    if (s.slice(start, start + length) === s.slice(i, i + length)) return i;
                }
                seen.get(h).push(i);
            } else {
                seen.set(h, [i]);
            }
        }
        return -1;
    }

    function modpow(base, exp, mod) {
        let result = 1n;
        base %= mod;
        while (exp > 0n) {
            if (exp % 2n === 1n) result = result * base % mod;
            base = base * base % mod;
            exp >>= 1n;
        }
        return result;
    }

    let lo = 0, hi = n - 1, start = 0, bestLen = 0;
    while (lo <= hi) {
        const mid = (lo + hi) >> 1;
        const idx = check(mid);
        if (idx !== -1) { bestLen = mid; start = idx; lo = mid + 1; }
        else hi = mid - 1;
    }
    return s.slice(start, start + bestLen);
};

