class Solution:
    def backspaceCompare(self, s: str, t: str) -> bool:
        def build(string):
            stack = []
            for c in string:
                if c != '#':
                    stack.append(c)
                elif stack:
                    stack.pop()
            return stack
        return build(s) == build(t)

solution_js:
var backspaceCompare = function(s, t) {
    function build(str) {
        const stack = [];
        for (const c of str) {
            if (c !== '#') stack.push(c);
            else if (stack.length) stack.pop();
        }
        return stack.join('');
    }
    return build(s) === build(t);
};

