class Solution:
    def isPossibleDivide(self, nums: List[int], k: int) -> bool:
        if len(nums) % k != 0:
            return False
        count = {}
        for n in nums:
            count[n] = count.get(n, 0) + 1
        for n in sorted(count):
            freq = count[n]
            if freq > 0:
                for i in range(k):
                    if count.get(n + i, 0) < freq:
                        return False
                    count[n + i] -= freq
        return True

solution_js:
var isPossibleDivide = function(nums, k) {
    if (nums.length % k !== 0) return false;
    const count = new Map();
    for (const n of nums) count.set(n, (count.get(n) || 0) + 1);
    for (const n of [...count.keys()].sort((a, b) => a - b)) {
        const freq = count.get(n);
        if (freq > 0) {
            for (let i = 0; i < k; i++) {
                if ((count.get(n + i) || 0) < freq) return false;
                count.set(n + i, count.get(n + i) - freq);
            }
        }
    }
    return true;
};

var canTransform = function(start, end) {
    if (start.replace(/X/g, '') !== end.replace(/X/g, '')) return false;
    let i = 0, j = 0, n = start.length;
    while (i < n && j < n) {
        while (i < n && start[i] === 'X') i++;
        while (j < n && end[j] === 'X') j++;
        if (i === n && j === n) return true;
        if (i === n || j === n) return false;
        if (start[i] !== end[j]) return false;
        if (start[i] === 'L' && i < j) return false;
        if (start[i] === 'R' && i > j) return false;
        i++; j++;
    }
    return true;
};

