class Solution:
    def sumSubarrayMins(self, arr: List[int]) -> int:
        MOD = 10**9 + 7
        n = len(arr)
        left = [0] * n  # number of subarrays ending at i with arr[i] as min
        right = [0] * n  # number of subarrays starting at i with arr[i] as min
        stack = []
        for i in range(n):
            while stack and arr[stack[-1]] >= arr[i]:
                stack.pop()
            left[i] = i - stack[-1] if stack else i + 1
            stack.append(i)
        stack = []
        for i in range(n - 1, -1, -1):
            while stack and arr[stack[-1]] > arr[i]:
                stack.pop()
            right[i] = stack[-1] - i if stack else n - i
            stack.append(i)
        return sum(arr[i] * left[i] * right[i] for i in range(n)) % MOD

solution_js:
var sumSubarrayMins = function(arr) {
    const MOD = 1e9 + 7;
    const n = arr.length;
    const left = new Array(n).fill(0);
    const right = new Array(n).fill(0);
    let stack = [];
    for (let i = 0; i < n; i++) {
        while (stack.length && arr[stack[stack.length-1]] >= arr[i]) stack.pop();
        left[i] = stack.length ? i - stack[stack.length-1] : i + 1;
        stack.push(i);
    }
    stack = [];
    for (let i = n - 1; i >= 0; i--) {
        while (stack.length && arr[stack[stack.length-1]] > arr[i]) stack.pop();
        right[i] = stack.length ? stack[stack.length-1] - i : n - i;
        stack.push(i);
    }
    let ans = 0;
    for (let i = 0; i < n; i++) ans = (ans + arr[i] * left[i] * right[i]) % MOD;
    return ans;
};

